debug_info.goal:
n : ℕ
hn : 1 ≤ n
a : ↥(Finset.Icc 1 n) → ℝ
hpos : ∀ (i : ↥(Finset.Icc 1 n)), 0 < a i
⊢ let harmonic := ↑n / ∑ i, 1 / a i;
  let geometric := (∏ i, a i) ^ (1 / ↑n);
  let arithmetic := (∑ i, a i) / ↑n;
  let all_equal := ∀ (i : ↥(Finset.Icc 1 n)), a i = a ⟨1, ⋯⟩;
  harmonic ≤ geometric ∧
    geometric ≤ arithmetic ∧ (harmonic = geometric ↔ all_equal) ∧ (geometric = arithmetic ↔ all_equal)
